        "for (_.i = 0, _.c = 2, _.d = 3; _.i < 1000; _.i++);");
    test("for (var i = 0, c = 2, d = 3, e = 4; i < 1000; i++);",
        "for (_.i = 0, _.c = 2, _.d = 3, _.e = 4; _.i < 1000; _.i++);");
